section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-rest-design.json",
  "title": "API REST Design",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "base_url",
    "resources",
    "verb_semantics",
    "status_code_map",
    "idempotency_header",
    "hateoas",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "base_url": {
      "type": "string",
      "description": "https://api.example.com/v1",
      "minLength": 1
    },
    "resources": {
      "type": "array",
      "description": "list of {name, collection_url, item_url, allowed_verbs}",
      "minItems": 1
    },
    "verb_semantics": {
      "type": "object",
      "description": "map verb \u2192 semantics (idempotent, safe, body-required)"
    },
    "status_code_map": {
      "type": "object",
      "description": "map outcome \u2192 status code (created\u2192201, validation-error\u2192422, conflict\u2192409)"
    },
    "idempotency_header": {
      "type": "string",
      "description": "header name; conventionally Idempotency-Key on POST/DELETE",
      "minLength": 1
    },
    "hateoas": {
      "type": "boolean",
      "description": "true when responses include rel-link objects"
    }
  },
  "additionalProperties": false
}
